def build_huffman_table(bits: list[int], values: list[int]) -> HuffmanTable:
    code = 0
    lookup: dict[int, int] = {}
    max_code_length = 0
    value_index = 0
    for length, count in enumerate(bits, start=1):
        if count == 0:
            code <<= 1
            continue
        for _ in range(count):
            lookup[(code, length)] = values[value_index]
            code += 1
            value_index += 1
            max_code_length = max(max_code_length, length)
        code <<= 1
    return HuffmanTable(
        bits=bits,
        values=values,
        lookup=lookup,
        value_set=set(values),
        max_code_length=max_code_length,
    )

