def decode_huffman_value(bit_reader: "BitReader", table: HuffmanTable) -> int:
    code = 0
    for length in range(1, 17):
        code = (code << 1) | bit_reader.read_bit()
        symbol = table.lookup.get((code, length))
        if symbol is not None:
            return symbol
    raise ValueError("Invalid Huffman code.")

