def encode_huffman_value(bit_writer: "BitWriter", table: HuffmanTable, value: int) -> None:
    if value not in table.value_set:
        raise ValueError(f"Value {value} is not present in Huffman table.")
    for (code, length), symbol in table.lookup.items():
        if symbol == value:
            bit_writer.write_bits(code, length)
            return
    raise ValueError(f"Value {value} is not present in Huffman table.")

