def encode_ac_coefficient(
    bit_writer: "BitWriter",
    table: HuffmanTable,
    zero_run: int,
    coefficient: int,
) -> None:
    """Encode one AC coefficient using only symbols present in the table."""
    magnitude_category = category(coefficient)
    if magnitude_category == 0:
        return

    while zero_run >= 16:
        encode_huffman_value(bit_writer, table, 0xF0)
        zero_run -= 16

    while zero_run > 0:
        symbol = (zero_run << 4) | magnitude_category
        if symbol in table.value_set:
            encode_huffman_value(bit_writer, table, symbol)
            encode_signed_magnitude(bit_writer, coefficient)
