class BitReader:
    def __init__(self, data: bytes) -> None:
        self.data = data
        self.byte_index = 0
        self.bit_index = 0

    def read_bit(self) -> int:
        if self.byte_index >= len(self.data):
            raise ValueError("Unexpected end of entropy data.")
        bit = (self.data[self.byte_index] >> (7 - self.bit_index)) & 1
        self.bit_index += 1
        if self.bit_index == 8:
            self.bit_index = 0
            self.byte_index += 1
            if self.byte_index < len(self.data) and self.data[self.byte_index - 1] == 0xFF:
                next_byte = self.data[self.byte_index]
                if next_byte == 0x00:
                    self.byte_index += 1
                elif next_byte == 0xD9:
                    self.byte_index = len(self.data)
                elif 0xD0 <= next_byte <= 0xD7:
                    self.byte_index += 1
                elif next_byte == 0xFF:
                    pass
                else:
                    self.byte_index += 1
        return bit

    def read_bits(self, count: int) -> int:
        value = 0
        for _ in range(count):
            value = (value << 1) | self.read_bit()
        return value

