class BitWriter:
    def __init__(self) -> None:
        self.buffer = bytearray()
        self.current_byte = 0
        self.bits_in_byte = 0

    def write_bits(self, value: int, count: int) -> None:
        for bit_index in range(count - 1, -1, -1):
            bit = (value >> bit_index) & 1
            self.current_byte = (self.current_byte << 1) | bit
            self.bits_in_byte += 1
            if self.bits_in_byte == 8:
                self._emit_byte(self.current_byte)
                self.current_byte = 0
                self.bits_in_byte = 0

    def _emit_byte(self, value: int) -> None:
        self.buffer.append(value)
        if value == 0xFF:
            self.buffer.append(0x00)

    def flush(self) -> bytes:
        if self.bits_in_byte:
            self.current_byte <<= 8 - self.bits_in_byte
            self._emit_byte(self.current_byte)
            self.current_byte = 0
            self.bits_in_byte = 0
        return bytes(self.buffer)

