def encode_signed_magnitude(bit_writer: BitWriter, value: int) -> None:
    if value == 0:
        return
    length = category(value)
    if value < 0:
        encoded = value + ((1 << length) - 1)
    else:
        encoded = value
    bit_writer.write_bits(encoded, length)

